package test.rice;

import main.rice.PrimeFactorizer;
import org.junit.jupiter.api.Test;

import static org.junit.jupiter.api.Assertions.assertArrayEquals;
import static org.junit.jupiter.api.Assertions.assertNull;

/**
 * Agent tests for PrimeFactorizer covering edge cases and various inputs.
 */
public class PrimeFactorizerAgentTest {

    private static final PrimeFactorizer smallFactorizer = new PrimeFactorizer(100);
    private static final PrimeFactorizer largeFactorizer = new PrimeFactorizer(50000000);

    // Edge cases: return null
    @Test
    void testFactorize1() {
        assertNull(smallFactorizer.computePrimeFactorization(1));
    }

    @Test
    void testFactorizeLargeNegative() {
        assertNull(smallFactorizer.computePrimeFactorization(-100));
    }

    @Test
    void testFactorize102ExceedsMax() {
        assertNull(smallFactorizer.computePrimeFactorization(102));
    }

    // Prime numbers
    @Test
    void testFactorize2() {
        assertArrayEquals(new int[]{2}, smallFactorizer.computePrimeFactorization(2));
    }

    @Test
    void testFactorize3() {
        assertArrayEquals(new int[]{3}, smallFactorizer.computePrimeFactorization(3));
    }

    @Test
    void testFactorize97() {
        assertArrayEquals(new int[]{97}, smallFactorizer.computePrimeFactorization(97));
    }

    // Composite numbers
    @Test
    void testFactorize4() {
        assertArrayEquals(new int[]{2, 2}, smallFactorizer.computePrimeFactorization(4));
    }

    @Test
    void testFactorize12() {
        assertArrayEquals(new int[]{2, 2, 3}, smallFactorizer.computePrimeFactorization(12));
    }

    @Test
    void testFactorize100() {
        assertArrayEquals(new int[]{2, 2, 5, 5}, smallFactorizer.computePrimeFactorization(100));
    }

    @Test
    void testFactorize60() {
        assertArrayEquals(new int[]{2, 2, 3, 5}, smallFactorizer.computePrimeFactorization(60));
    }

    @Test
    void testFactorize8() {
        assertArrayEquals(new int[]{2, 2, 2}, smallFactorizer.computePrimeFactorization(8));
    }

    @Test
    void testFactorize30() {
        assertArrayEquals(new int[]{2, 3, 5}, smallFactorizer.computePrimeFactorization(30));
    }

    // Exact boundary
    @Test
    void testFactorizeExactMax() {
        assertArrayEquals(new int[]{2, 2, 5, 5}, smallFactorizer.computePrimeFactorization(100));
    }

    // Large factorizer tests
    @Test
    void testLargeFactorizePrime() {
        // 49999991 is a prime
        assertArrayEquals(new int[]{49999991}, largeFactorizer.computePrimeFactorization(49999991));
    }

    @Test
    void testLargeFactorize2() {
        assertArrayEquals(new int[]{2}, largeFactorizer.computePrimeFactorization(2));
    }

    @Test
    void testLargeFactorizePowerOf2() {
        // 2^25 = 33554432
        assertArrayEquals(new int[]{2, 2, 2, 2, 2, 2, 2, 2, 2, 2, 2, 2, 2, 2, 2, 2, 2, 2, 2, 2, 2, 2, 2, 2, 2},
                largeFactorizer.computePrimeFactorization(33554432));
    }

    @Test
    void testLargeFactorizeComposite() {
        // 50000000 = 2^5 * 5^8 = 2*2*2*2*2 * 5*5*5*5*5*5*5*5?
        // 5^8 = 390625, 2^5 = 32, 32*390625 = 12500000. Not 50000000.
        // 50000000 = 5 * 10^7 = 5 * 10000000 = 5 * 2^7 * 5^7...
        // 50000000 = 2^7 * 5^7 * ... let me compute: 50000000 / 2 = 25000000 / 2 = 12500000 / 2 = 6250000 / 2 = 3125000 / 2 = 1562500 / 2 = 781250 / 2 = 390625
        // So 50000000 = 2^7 * 390625 = 2^7 * 5^8
        assertArrayEquals(new int[]{2, 2, 2, 2, 2, 2, 2, 5, 5, 5, 5, 5, 5, 5, 5},
                largeFactorizer.computePrimeFactorization(50000000));
    }

    @Test
    void testLargeExceedsMax() {
        assertNull(largeFactorizer.computePrimeFactorization(50000001));
    }
}
